import { defineComponent, computed, h } from 'vue';
import { getTextareaIds, getTextareaAriaProps } from '../lib/core';
import styles from './textarea.module.scss';

let textareaCounter = 0;

export const TTextarea = defineComponent({
  name: 'TTextarea',
  props: {
    label: String,
    error: String,
    helperText: String,
    required: { type: Boolean, default: false },
    id: String,
    placeholder: String,
    modelValue: String,
    disabled: { type: Boolean, default: false },
  },
  emits: ['update:modelValue'],
  setup(props, { emit }) {
    const textareaId = computed(() => props.id || `tile-textarea-${++textareaCounter}`);
    const ids = computed(() => getTextareaIds(textareaId.value));
    const ariaProps = computed(() => getTextareaAriaProps(ids.value, props.error, props.helperText));

    function onInput(event: Event) {
      emit('update:modelValue', (event.target as HTMLTextAreaElement).value);
    }

    return () => {
      const children: any[] = [];

      if (props.label) {
        children.push(
          h('label', {
            for: textareaId.value,
            class: [styles.label, props.required ? styles.required : ''],
          }, props.label)
        );
      }

      children.push(
        h('textarea', {
          id: textareaId.value,
          class: [styles.textarea, props.error ? styles.error : ''],
          value: props.modelValue,
          placeholder: props.placeholder,
          disabled: props.disabled,
          'aria-invalid': ariaProps.value['aria-invalid'],
          'aria-describedby': ariaProps.value['aria-describedby'],
          onInput,
        })
      );

      if (props.error) {
        children.push(
          h('span', { id: ids.value.error, class: styles.errorText }, props.error)
        );
      } else if (props.helperText) {
        children.push(
          h('span', { id: ids.value.helper, class: styles.helperText }, props.helperText)
        );
      }

      return h('div', { class: styles.textareaWrapper }, children);
    };
  },
});

export default TTextarea;

@use 'sass:color';
@use 'variables/colors' as *;

.textareaWrapper {
  display: flex;
  flex-direction: column;
  gap: $spacing-1;
  width: 100%;
}

.textarea {
  display: flex;
  min-height: 5rem;
  width: 100%;
  border-radius: $radius;
  border: 1px solid $border;
  background-color: $background;
  padding: $spacing-3 $spacing-3;
  font-size: $text-sm;
  color: $foreground;
  transition: all $transition-fast;
  outline: none;
  resize: vertical;
  font-family: inherit;
  line-height: $leading-normal;

  &::placeholder {
    color: color.mix(white, $foreground, 60%);
  }

  &:focus {
    outline: none;
    border-color: $ring;
    box-shadow: 0 0 0 1px $ring;
  }

  &:disabled,
  &.disabled {
    pointer-events: none;
    opacity: 0.5;
    cursor: not-allowed;
    background-color: color.mix(white, $background, 50%);
  }

  &.error {
    border-color: $destructive;

    &:focus {
      border-color: $destructive;
      box-shadow: 0 0 0 1px $destructive;
    }
  }
}

.label {
  display: block;
  font-size: $text-sm;
  font-weight: $font-medium;
  color: $foreground;
  line-height: $leading-normal;

  &.required::after {
    content: ' *';
    color: $destructive;
  }
}

.helperText {
  font-size: $text-xs;
  color: color.mix(white, $foreground, 60%);
  line-height: $leading-normal;
}

.errorText {
  font-size: $text-xs;
  color: $destructive;
  line-height: $leading-normal;
}
